// ============================================================================
// EF Core 9 – Cosmos DB Breaking Changes & Required Fixes
// Apply these patterns to your Cosmos DB project.
// ============================================================================

using Microsoft.EntityFrameworkCore;

// ---------------------------------------------------------------------------
// BREAKING CHANGE 1: Discriminator property renamed from "Discriminator" to "$type"
//
// EF Core 9 now uses "$type" by default. Existing documents stored with
// "Discriminator" will NOT match unless you explicitly configure the old name.
// ---------------------------------------------------------------------------
class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Fix: explicitly set the discriminator property name to match existing documents
        modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");
    }
}

class Product
{
    public string Id { get; set; } = "";
    public string Name { get; set; } = "";
}

// ---------------------------------------------------------------------------
// BREAKING CHANGE 2: Synchronous Cosmos DB I/O now throws
//
// EF Core 9 removed sync-over-async for the Cosmos provider.
// All queries and SaveChanges calls MUST use async equivalents.
// ---------------------------------------------------------------------------
class CosmosQueryExamples
{
    // BEFORE (EF Core 8 – sync, now throws InvalidOperationException in EF Core 9):
    //
    //   var products = db.Products.ToList();
    //   var first    = db.Products.First(p => p.Name == "X");
    //   db.SaveChanges();

    // AFTER (EF Core 9 – async required):
    async Task FixedExamplesAsync(CosmosDbContext db)
    {
        var products = await db.Products.ToListAsync();
        var first = await db.Products.FirstAsync(p => p.Name == "X");
        await db.SaveChangesAsync();
    }
}

